<?php
namespace App\Services;use App\Models\Leave;use Illuminate\Support\Facades\DB;use Illuminate\Validation\ValidationException;
class LeaveBalanceService{public function consume(Leave$leave,?int$userId=null):void{if(!$leave->leave_type_id)return;$type=DB::table('leave_types')->find($leave->leave_type_id);if(!$type)return;$days=(float)($leave->requested_days??$leave->total_days);$year=(int)$leave->start_date->year;$reference='leave:'.$leave->id;if(DB::table('leave_transactions')->where(['employee_id'=>$leave->employee_id,'leave_type_id'=>$leave->leave_type_id,'source'=>'approved_leave','reference'=>$reference])->exists())return;$balance=DB::table('leave_balances')->where(['employee_id'=>$leave->employee_id,'leave_type_id'=>$leave->leave_type_id,'year'=>$year])->lockForUpdate()->first();$available=$balance?(float)$balance->opening_balance+(float)$balance->accrued+(float)$balance->adjusted-(float)$balance->used-(float)$balance->encashed:0;if($type->is_paid&&$available<$days)throw ValidationException::withMessages(['leave_balance'=>"Insufficient {$type->name} balance. Available: {$available}"]);if(!$balance){DB::table('leave_balances')->insert(['employee_id'=>$leave->employee_id,'leave_type_id'=>$leave->leave_type_id,'year'=>$year,'used'=>0,'created_at'=>now(),'updated_at'=>now()]);}DB::table('leave_balances')->where(['employee_id'=>$leave->employee_id,'leave_type_id'=>$leave->leave_type_id,'year'=>$year])->increment('used',$days,['updated_at'=>now()]);DB::table('leave_transactions')->insert(['employee_id'=>$leave->employee_id,'leave_type_id'=>$leave->leave_type_id,'year'=>$year,'type'=>'usage','amount'=>-$days,'source'=>'approved_leave','reference'=>$reference,'created_by'=>$userId,'created_at'=>now(),'updated_at'=>now()]);}}
